#include <bits/stdc++.h>
using namespace std;
int n,m;
vector<int> g[26];
bool tuopu(int x){
    bool flag=true;
    queue<int> s,t;
    int d[26];
    memset(d,0,sizeof(d));
    for(int i=0;i<n;i++){
        int len=g[i].size();
        for(int j=0;j<len;j++)
            d[g[i][j]]++;
    }
    for(int i=0;i<n;i++)
        if(!d[i])
            t.push(i);
    if(t.empty()){
        printf("Inconsistency found after %d relations.",x);
        return true;
    }
    if(t.size()>1)
        flag=false;
    int tot=0;
    while(t.size()){
        tot++;
        s.push(t.front()),t.pop();
        if(tot==n)
            break;
        int u=s.back(),len=g[u].size();
        for(int i=0;i<len;i++)
            if(!--d[g[u][i]])
                t.push(g[u][i]);
        if(t.empty()){
            printf("Inconsistency found after %d relations.",x);
            return true;
        }
        if(t.size()>1)
            flag=false;
    }
    if(!flag)
        return false;
    printf("Sorted sequence determined after %d relations: ",x);
    while(s.size()){
        printf("%c",(char)s.front()+'A');
        s.pop();
    }
    printf(".");
    return true;
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        string s;
        cin>>s;
        g[s[0]-'A'].push_back(s[2]-'A');
        //printf("%d %d\n",s[0]-'A',s[2]-'A');
        if(tuopu(i))
            return 0;
    }
    printf("Sorted sequence cannot be determined.");
    return 0;
}
